273	// mergeOutcomeFromVerdict normalizes the bundle verdict/status into the
274	// {merged, preserved} space the try layer reports.
275	func mergeOutcomeFromVerdict(exec *ddxgraphql.Execution) string {
276		v := ""
277		if exec.Verdict != nil {
278			v = strings.ToLower(*exec.Verdict)
279		}
280		if v == "" && exec.Status != nil {
281			v = strings.ToLower(*exec.Status)
282		}
283		switch v {
284		case "preserved", "preserve":
285			return "preserved"
286		case "merged", "merge", "success", "pass":
287			if exec.ResultRev != nil && *exec.ResultRev != "" {
288				return "merged"
289			}
290			return ""
291		}
292		return ""
293	}
