102	// resolveRunBundlePath canonicalises a user-supplied path (relative to the
103	// bundle root) and returns the absolute filesystem path inside the bundle.
104	// It rejects:
105	//   - absolute paths
106	//   - paths containing ".." that escape the root
107	//   - symlink targets that resolve outside the root
108	//
109	// All three rejection modes return errRunBundleOutsideRoot. The path argument
110	// must use forward slashes (or be normalisable to them).
111	func resolveRunBundlePath(bundleRoot, path string) (string, error) {
112		if path == "" {
113			return "", errRunBundleOutsideRoot
114		}
115		if filepath.IsAbs(path) || strings.HasPrefix(path, "/") {
116			return "", errRunBundleOutsideRoot
117		}
118		clean := filepath.Clean(filepath.FromSlash(path))
119		if clean == "." || clean == ".." || strings.HasPrefix(clean, ".."+string(filepath.Separator)) {
120			return "", errRunBundleOutsideRoot
121		}
122		full := filepath.Join(bundleRoot, clean)
123		// Re-clean and confirm it sits under bundleRoot.
124		full = filepath.Clean(full)
125		rel, err := filepath.Rel(bundleRoot, full)
126		if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
127			return "", errRunBundleOutsideRoot
128		}
129		// If the file (or any parent) is a symlink, confirm the eval'd target
130		// also remains inside the canonical bundleRoot. Missing files are OK to
131		// pass through here — the caller will return 404 when reading.
132		if eval, err := filepath.EvalSymlinks(full); err == nil {
133			evalClean := filepath.Clean(eval)
134			rel2, err := filepath.Rel(bundleRoot, evalClean)
135			if err != nil || rel2 == ".." || strings.HasPrefix(rel2, ".."+string(filepath.Separator)) {
136				return "", errRunBundleOutsideRoot
137			}
138		}
139		return full, nil
140	}
